    setAutoLayout(copyColumn, "VERTICAL", 14, 0);
    copyColumn.layoutSizingVertical = "HUG";
    const markerColor = [PORTFOLIO_MODEL.tokens.coral, PORTFOLIO_MODEL.tokens.cobalt, PORTFOLIO_MODEL.tokens.moss][index % 3];
